<script>
    $(document).ready(function() {

        // Función para cargar y aplicar el modo guardado
        function aplicarModoGuardado() {
            const modoGuardado = localStorage.getItem("modo");
            
            if (modoGuardado === "oscuro") {
                // Modo oscuro/nocturno
                $("body").removeClass("modo-claro").addClass("modo-oscuro");
                $("#modo-icon").removeClass("fa-sun").addClass("fa-moon");
                $("#modo-btn").removeClass("btn-outline-dark").addClass("btn-outline-light");
                
                $('.container-main').css('background', 'linear-gradient(rgba(0, 0, 0, 0.8), rgba(0, 0, 0, 0.8)), url("../imgC/fondo2.png")');
                $('.pagination a').css('color', 'white').css('border-color', 'white');
                $('#unico, .unico, #pp').css('color', 'white');
                $('hr').css('border-color', 'white');
            } else {
                // Modo claro/diurno (por defecto)
                $("body").removeClass("modo-oscuro").addClass("modo-claro");
                $("#modo-icon").removeClass("fa-moon").addClass("fa-sun");
                $("#modo-btn").removeClass("btn-outline-light").addClass("btn-outline-dark");
                
                $('.container-main').css('background', 'linear-gradient(rgba(255, 255, 255, 0.8), rgba(255, 255, 255, 0.8)), url("../imgC/fondo2.png")');
                $('.pagination a').css('color', 'black').css('border-color', 'black');
                $('#unico, .unico, #pp').css('color', 'black');
                $('hr').css('border-color', 'black');
            }
        }

        // Cargar modo guardado al iniciar
        aplicarModoGuardado();

        // Evento para cambiar el modo al hacer clic en el botón
        $("#modo-btn").click(function() {
            $("body").toggleClass("modo-claro modo-oscuro");

            if ($("body").hasClass("modo-oscuro")) {
                // Cambiar a modo oscuro
                $("#modo-icon").removeClass("fa-sun").addClass("fa-moon");
                $("#modo-btn").removeClass("btn-outline-dark").addClass("btn-outline-light");
                localStorage.setItem("modo", "oscuro");
                
                $('.container-main').css('background', 'linear-gradient(rgba(0, 0, 0, 0.8), rgba(0, 0, 0, 0.8)), url("../imgC/fondo2.png")');
                $('.pagination a').css('color', 'white').css('border-color', 'white');
                $('#unico, .unico, #pp').css('color', 'white');
                $('hr').css('border-color', 'white');
            } else {
                // Cambiar a modo claro
                $("#modo-icon").removeClass("fa-moon").addClass("fa-sun");
                $("#modo-btn").removeClass("btn-outline-light").addClass("btn-outline-dark");
                localStorage.setItem("modo", "claro");
                
                $('.container-main').css('background', 'linear-gradient(rgba(255, 255, 255, 0.8), rgba(255, 255, 255, 0.8)), url("../imgC/fondo2.png")');
                $('.pagination a').css('color', 'black').css('border-color', 'black');
                $('#unico, .unico, #pp').css('color', 'black');
                $('hr').css('border-color', 'black');
            }
        });

    });
</script>
    
